@Action
def is_ani_in_wireless_subscriptions() -> bool:
    """Returns True if the ANI exists in Phone subscriptions; otherwise False."""
    
    subscriptions = state["$session.params.subscriptionsList"]
    identifiedPhoneNumber = state["$session.params.reportingVar_ANI"]
    
    if not subscriptions or not identifiedPhoneNumber:
        return False
  
    for item in subscriptions:
        service_category = item.get("serviceCategory", {}).get("french")
        if service_category == "Mobile":
            if item.get("subscriptionSerialNumber") == identifiedPhoneNumber:
                return True
    
    return False
